 * Pool allocateur simple (taille fixe)
 * Pattern: buffer statique + bitmap d'occupation
 * ================================================= */
#define POOL_SLOTS 4
#define SLOT_SIZE 16
static char pool[POOL_SLOTS * SLOT_SIZE];
static int pool_used[POOL_SLOTS] = {0};

void *pool_alloc(void) {
    for (int i = 0; i < POOL_SLOTS; i++)
        if (!pool_used[i]) { pool_used[i] = 1; return &pool[i*SLOT_SIZE]; }
    return NULL;
}
void pool_free(void *ptr) {
    int idx = ((char*)ptr - pool) / SLOT_SIZE;
    if (idx >= 0 && idx < POOL_SLOTS) pool_used[idx] = 0;
}
void example_pool(void) {
    void *a = pool_alloc(); void *b = pool_alloc();
    memset(a, 'X', SLOT_SIZE); memset(b, 'Y', SLOT_SIZE);
    printf("Slots used: %d, %d\n", pool_used[0], pool_used[1]);
    pool_free(a);
    printf("After free: %d, %d\n", pool_used[0], pool_used[1]);
